/**
 * Admin Contact Sales Management Page
 * Author: generated by Amazon Q
 * Created: 2024-01-20
 */

'use client';

import { useState, useEffect } from 'react';
import { Globe, Plus, Edit, Trash2, Eye, EyeOff, Copy, Save } from 'lucide-react';

interface ContactSalesButton {
  id: string;
  language: string;
  show: boolean;
  text: string;
  url: string;
  isActive: boolean;
}

const languageFlags: Record<string, string> = {
  en: '🇺🇸',
  ar: '🇸🇦',
  tr: '🇹🇷',
  fr: '🇫🇷',
  de: '🇩🇪',
  es: '🇪🇸',
  fa: '🇮🇷'
};

const languageNames: Record<string, string> = {
  en: 'English',
  ar: 'العربية',
  tr: 'Türkçe',
  fr: 'Français',
  de: 'Deutsch',
  es: 'Español',
  fa: 'فارسی'
};

export default function ContactSalesPage() {
  const [buttons, setButtons] = useState<ContactSalesButton[]>([]);
  const [loading, setLoading] = useState(true);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [editData, setEditData] = useState({ text: '', url: '' });
  const [showAddModal, setShowAddModal] = useState(false);
  const [newButton, setNewButton] = useState({ language: 'en', text: 'Contact Sales', url: '/en/contact-sales' });

  useEffect(() => {
    fetchButtons();
  }, []);

  const fetchButtons = async () => {
    try {
      const token = localStorage.getItem('adminToken');
      const response = await fetch('/api/admin/contact-sales', {
        headers: { 'Authorization': `Bearer ${token}` },
      });
      if (response.ok) {
        const data = await response.json();
        setButtons(data.buttons || []);
      }
    } catch (error) {
      console.error('Failed to fetch buttons:', error);
    } finally {
      setLoading(false);
    }
  };

  const toggleActive = async (id: string, currentStatus: boolean) => {
    try {
      const token = localStorage.getItem('adminToken');
      const button = buttons.find(b => b.id === id);
      if (!button) return;

      const response = await fetch(`/api/admin/contact-sales/${id}`, {
        method: 'PUT',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ...button,
          isActive: !currentStatus
        }),
      });

      if (response.ok) {
        fetchButtons();
      }
    } catch (error) {
      console.error('Failed to toggle status:', error);
    }
  };

  const startEdit = (button: ContactSalesButton) => {
    setEditingId(button.id);
    setEditData({ text: button.text, url: button.url });
  };

  const saveEdit = async (id: string) => {
    try {
      const token = localStorage.getItem('adminToken');
      const button = buttons.find(b => b.id === id);
      if (!button) return;

      const response = await fetch(`/api/admin/contact-sales/${id}`, {
        method: 'PUT',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          ...button,
          text: editData.text,
          url: editData.url
        }),
      });

      if (response.ok) {
        alert('✅ Saved successfully!');
        setEditingId(null);
        fetchButtons();
      }
    } catch (error) {
      console.error('Failed to save:', error);
      alert('❌ Failed to save');
    }
  };

  const deleteButton = async (id: string) => {
    if (!confirm('Are you sure you want to delete this button?')) return;

    try {
      const token = localStorage.getItem('adminToken');
      const response = await fetch(`/api/admin/contact-sales/${id}`, {
        method: 'DELETE',
        headers: { 'Authorization': `Bearer ${token}` },
      });

      if (response.ok) {
        alert('✅ Deleted successfully!');
        fetchButtons();
      }
    } catch (error) {
      console.error('Failed to delete:', error);
      alert('❌ Failed to delete');
    }
  };

  const addButton = async () => {
    try {
      const token = localStorage.getItem('adminToken');
      const response = await fetch('/api/admin/contact-sales', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(newButton),
      });

      if (response.ok) {
        alert('✅ Button created successfully!');
        setShowAddModal(false);
        setNewButton({ language: 'en', text: 'Contact Sales', url: '/en/contact-sales' });
        fetchButtons();
      } else {
        const data = await response.json();
        alert(`❌ ${data.error || 'Failed to create button'}`);
      }
    } catch (error) {
      console.error('Failed to create button:', error);
      alert('❌ Failed to create button');
    }
  };

  const usedLanguages = buttons.map(b => b.language);
  const availableLanguages = Object.keys(languageNames).filter(
    lang => !usedLanguages.includes(lang)
  );

  if (loading) {
    return (
      <div className="flex items-center justify-center min-h-screen">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-blue-600"></div>
      </div>
    );
  }

  return (
    <div>
      <div className="flex justify-between items-center mb-8">
        <div>
          <h1 className="text-3xl font-bold text-gray-900 dark:text-white">
            Contact Sales Buttons
          </h1>
          <p className="mt-2 text-gray-600 dark:text-gray-400">
            Manage contact sales button for different languages
          </p>
        </div>
        {availableLanguages.length > 0 && (
          <button
            onClick={() => setShowAddModal(true)}
            className="bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-medium transition-colors flex items-center gap-2"
          >
            <Plus className="w-4 h-4" />
            Add Button
          </button>
        )}
      </div>

      {buttons.length === 0 ? (
        <div className="text-center py-12 bg-white dark:bg-gray-800 rounded-lg shadow">
          <div className="text-6xl mb-4">📞</div>
          <h3 className="text-xl font-semibold text-gray-900 dark:text-white mb-2">
            No buttons found
          </h3>
          <p className="text-gray-600 dark:text-gray-400 mb-4">
            Create your first contact sales button
          </p>
          <button
            onClick={() => setShowAddModal(true)}
            className="inline-flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg font-medium transition-colors"
          >
            <Plus className="w-4 h-4" />
            Add Button
          </button>
        </div>
      ) : (
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
          {buttons.map((button) => (
            <div
              key={button.id}
              className="bg-white dark:bg-gray-800 rounded-lg shadow p-6"
            >
              <div className="flex items-start justify-between mb-4">
                <div className="flex items-center gap-2">
                  <span className="text-2xl">{languageFlags[button.language] || '🌐'}</span>
                  <h3 className="text-lg font-semibold text-gray-900 dark:text-white">
                    {languageNames[button.language] || button.language.toUpperCase()}
                  </h3>
                </div>
                <button
                  onClick={() => toggleActive(button.id, button.isActive)}
                  className={`p-2 rounded-lg transition-colors ${
                    button.isActive
                      ? 'bg-green-100 text-green-600 dark:bg-green-900/20 dark:text-green-400'
                      : 'bg-gray-100 text-gray-400 dark:bg-gray-700 dark:text-gray-500'
                  }`}
                >
                  {button.isActive ? <Eye className="w-4 h-4" /> : <EyeOff className="w-4 h-4" />}
                </button>
              </div>

              {editingId === button.id ? (
                <div className="space-y-3">
                  <input
                    type="text"
                    value={editData.text}
                    onChange={(e) => setEditData({ ...editData, text: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white text-sm"
                    placeholder="Button Text"
                  />
                  <input
                    type="text"
                    value={editData.url}
                    onChange={(e) => setEditData({ ...editData, url: e.target.value })}
                    className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white text-sm"
                    placeholder="Button URL"
                  />
                  <div className="flex gap-2">
                    <button
                      onClick={() => saveEdit(button.id)}
                      className="flex-1 px-3 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 text-sm flex items-center justify-center gap-2"
                    >
                      <Save className="w-4 h-4" />
                      Save
                    </button>
                    <button
                      onClick={() => setEditingId(null)}
                      className="px-3 py-2 bg-gray-200 dark:bg-gray-700 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-300 dark:hover:bg-gray-600 text-sm"
                    >
                      Cancel
                    </button>
                  </div>
                </div>
              ) : (
                <>
                  <div className="mb-4">
                    <div className="text-sm font-medium text-gray-900 dark:text-white mb-1">
                      {button.text}
                    </div>
                    <div className="text-xs text-gray-500 dark:text-gray-400">
                      {button.url}
                    </div>
                  </div>
                  <div className="flex gap-2">
                    <button
                      onClick={() => startEdit(button)}
                      className="flex-1 px-3 py-2 bg-blue-50 dark:bg-blue-900/20 text-blue-600 dark:text-blue-400 rounded-lg hover:bg-blue-100 dark:hover:bg-blue-900/30 text-sm flex items-center justify-center gap-2"
                    >
                      <Edit className="w-4 h-4" />
                      Edit
                    </button>
                    <button
                      onClick={() => deleteButton(button.id)}
                      className="px-3 py-2 bg-red-50 dark:bg-red-900/20 text-red-600 dark:text-red-400 rounded-lg hover:bg-red-100 dark:hover:bg-red-900/30 text-sm"
                    >
                      <Trash2 className="w-4 h-4" />
                    </button>
                  </div>
                </>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Add Modal */}
      {showAddModal && (
        <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/50 backdrop-blur-sm">
          <div className="bg-white dark:bg-gray-800 rounded-lg shadow-xl w-full max-w-md mx-4 p-6">
            <h3 className="text-xl font-bold text-gray-900 dark:text-white mb-4">
              Add Contact Sales Button
            </h3>
            <div className="space-y-4">
              <div>
                <label className="block text-sm font-medium mb-2">Language</label>
                <select
                  value={newButton.language}
                  onChange={(e) => setNewButton({ ...newButton, language: e.target.value })}
                  className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                >
                  {availableLanguages.map(code => (
                    <option key={code} value={code}>
                      {languageFlags[code]} {languageNames[code]}
                    </option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-sm font-medium mb-2">Button Text</label>
                <input
                  type="text"
                  value={newButton.text}
                  onChange={(e) => setNewButton({ ...newButton, text: e.target.value })}
                  className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                  placeholder="Contact Sales"
                />
              </div>
              <div>
                <label className="block text-sm font-medium mb-2">Button URL</label>
                <input
                  type="text"
                  value={newButton.url}
                  onChange={(e) => setNewButton({ ...newButton, url: e.target.value })}
                  className="w-full px-3 py-2 border border-gray-300 dark:border-gray-600 rounded-lg bg-white dark:bg-gray-700 text-gray-900 dark:text-white"
                  placeholder="/en/contact-sales"
                />
              </div>
            </div>
            <div className="flex gap-3 mt-6">
              <button
                onClick={() => setShowAddModal(false)}
                className="flex-1 px-4 py-2 border border-gray-300 dark:border-gray-600 text-gray-700 dark:text-gray-300 rounded-lg hover:bg-gray-50 dark:hover:bg-gray-700"
              >
                Cancel
              </button>
              <button
                onClick={addButton}
                className="flex-1 px-4 py-2 bg-blue-600 text-white rounded-lg hover:bg-blue-700"
              >
                Create
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
